// Documenso webhook receiver for SignatureGate
// Works with Documenso events like:
// - "document.completed" (docs list)
// - "DOCUMENT_COMPLETED" (example payloads)
// Payload shape (docs): { event: string, payload: {...}, createdAt, webhookEndpoint }

const body = $json.body ?? $json; // webhook node can output either raw body or {body:...}
const eventRaw = body.event;
const payload = body.payload ?? {};

if (!eventRaw) throw new Error(`Missing webhook event. Body: ${JSON.stringify(body)}`);

// Normalize event to lowercase dot format: "document.completed"
const norm = (e) => {
  const s = String(e);
  // Common cases:
  //  - DOCUMENT_COMPLETED -> document.completed
  //  - document.completed -> document.completed
  //  - DOCUMENT.SENT -> document.sent
  const lower = s.toLowerCase();
  if (lower.includes(".")) return lower;
  return lower.replace(/_/g, ".");
};
const event = norm(eventRaw);

// Correlation: we rely on externalId = "ma:<uuid>" set during /envelope/use
const externalId = payload.externalId ?? payload.external_id ?? null;

let member_agreement_id = null;
if (externalId && typeof externalId === "string" && externalId.startsWith("ma:")) {
  member_agreement_id = externalId.slice(3);
}

// Documenso document id in webhook docs is numeric; in our system we store text.
// Keep as string for storage.
const docId = payload.id ?? payload.documentId ?? payload.document_id ?? null;
const documenso_document_id = (docId === null || docId === undefined) ? null : String(docId);

// Map Documenso event -> SignatureGate status
// (You can refine later to track partially-signed vs completed if desired.)
let status = null;
switch (event) {
  case "document.completed":
    status = "signed";
    break;
  case "document.rejected":
    status = "rejected";
    break;
  case "document.cancelled":
    status = "cancelled";
    break;
  case "document.sent":
    status = "pending_signature";
    break;
  case "document.opened":
    status = "pending_signature";
    break;
  case "document.signed":
    // one signer signed; still pending overall unless you track per-recipient.
    status = "pending_signature";
    break;
  default:
    // don't change status for events we aren't handling yet
    status = null;
}

return [{
  json: {
    event,
    eventRaw,
    status,
    externalId,
    member_agreement_id,
    documenso_document_id,
    payload,
    createdAt: body.createdAt ?? null
  }
}];
